SELECT rrf.RDB$FIELD_NAME FROM RDB$RELATION_FIELDS rrf WHERE rrf.RDB$RELATION_NAME = 'NOTA' AND (LOWER(TRIM(rrf.RDB$FIELD_NAME)) LIKE '%munic%' OR LOWER(TRIM(rrf.RDB$FIELD_NAME)) LIKE '%dest%' OR LOWER(TRIM(rrf.RDB$FIELD_NAME)) LIKE '%fim%' OR LOWER(TRIM(rrf.RDB$FIELD_NAME)) LIKE '%ini%') ORDER BY rrf.RDB$FIELD_POSITION;
